// Some portions generated by Codex
package org.eclipse.rdf4j.query.algebra.evaluation.optimizer.scope;

import static org.assertj.core.api.Assertions.assertThat;

import org.eclipse.rdf4j.model.impl.SimpleValueFactory;
import org.eclipse.rdf4j.query.QueryLanguage;
import org.eclipse.rdf4j.query.algebra.Join;
import org.eclipse.rdf4j.query.algebra.QueryRoot;
import org.eclipse.rdf4j.query.algebra.StatementPattern;
import org.eclipse.rdf4j.query.algebra.TupleExpr;
import org.eclipse.rdf4j.query.algebra.Var;
import org.eclipse.rdf4j.query.parser.QueryParserUtil;
import org.junit.jupiter.api.Test;
import org.openjdk.jol.info.GraphLayout;

class ScopeLayoutBudgetTest {

	@Test
	void narrowScopeStateFitsPerNodeBudget() {
		QueryRoot root = representativeAlgebra(512);
		long algebraBytes = GraphLayout.parseInstance(root).totalSize();
		try (ScopeAnalysis analysis = ScopeAnalysis.analyze(root)) {
			GraphLayout scopeLayout = GraphLayout.parseInstance(analysis);
			long scopeBytes = scopeLayout.totalSize() - algebraBytes;
			assertThat(scopeBytes)
					.as("scope state bytes for %s indexed nodes", analysis.arena().size())
					.isLessThanOrEqualTo(160L * analysis.arena().size());
		}
	}

	@Test
	void parserSeedFitsPerOccurrenceBudget() {
		StringBuilder query = new StringBuilder("SELECT * WHERE {\n");
		for (int index = 0; index < 256; index++) {
			query.append("?s <urn:p").append(index).append("> ?o .\n");
		}
		query.append('}');
		QueryRoot root = (QueryRoot) QueryParserUtil.parseQuery(QueryLanguage.SPARQL, query.toString(), null)
				.getTupleExpr();
		var seed = root.getQueryScopeSeed();
		assertThat(seed).isNotNull();
		assertThat(GraphLayout.parseInstance(seed).totalSize())
				.isLessThanOrEqualTo(96L * seed.getOccurrenceCount());
	}

	private static QueryRoot representativeAlgebra(int patterns) {
		TupleExpr expression = pattern();
		for (int index = 1; index < patterns; index++) {
			expression = new Join(expression, pattern());
		}
		return new QueryRoot(expression);
	}

	private static StatementPattern pattern() {
		return new StatementPattern(Var.of("subject"),
				Var.of("predicate", SimpleValueFactory.getInstance().createIRI("urn:p")), Var.of("object"));
	}
}
